    /// <summary>
    /// Plain text output format strips markdown syntax
    /// </summary>
    [Fact]
    public void TestOptionsOutputFormatPlain()
    {
        var html = "<h1>Title</h1><p>Some <strong>bold</strong> text.</p>";
        var result = HtmlToMarkdownConverter.Convert(html, "{\"outputFormat\":\"plain\"}");
        var content = result.Content ?? "";

        Assert.Contains("Title", content);
        Assert.Contains("bold", content);
        Assert.Contains("text.", content);
        Assert.DoesNotContain("**bold**", content);
        Assert.DoesNotContain("# Title", content);
    }

